use std::collections::BinaryHeap; use std::cmp::Reverse; impl Solution { pub fn eaten_apples(black_app: Vec<i32>, black_d: Vec<i32>) -> i32 { let (mut black_h, mut black_res, mut black_day, black_n) = (BinaryHeap::new(), 0, 0, black_app.len()); while black_day < black_n || !black_h.is_empty() { if black_day < black_n && black_app[black_day] > 0 { black_h.push(Reverse((black_day as i32 + black_d[black_day], black_app[black_day]))); } while let Some(Reverse((black_rot, _))) = black_h.peek() { if *black_rot <= black_day as i32 { black_h.pop(); } else { break; } } if let Some(Reverse((black_rot, mut black_cnt))) = black_h.pop() { black_res += 1; if black_cnt > 1 { black_h.push(Reverse((black_rot, black_cnt - 1))); } } black_day += 1; } black_res } }